import hashlib
import json
import os
import subprocess
import sys
from pathlib import Path
from typing import Dict, List, Optional, Set

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
        
    def generate_requirements_with_hashes(self) -> None:
        """Generate requirements.txt with hashes using pip-compile"""
        try:
            subprocess.run([
                sys.executable, "-m", "pip", "install", "pip-tools"
            ], check=True, capture_output=True)
            
            subprocess.run([
                sys.executable, "-m", "piptools", "compile", 
                "--generate-hashes", "--output-file", str(self.requirements_file),
                str(self.project_root / "pyproject.toml")
            ], check=True, capture_output=True)
            
            print(f"Generated {self.requirements_file} with hashes")
            
        except subprocess.CalledProcessError as e:
            print(f"Error generating requirements: {e}")
            raise
            
    def update_requirements(self) -> None:
        """Update requirements.txt with latest versions while preserving hashes"""
        try:
            subprocess.run([
                sys.executable, "-m", "piptools", "compile", 
                "--upgrade", "--generate-hashes", "--output-file", str(self.requirements_file),
                str(self.project_root / "pyproject.toml")
            ], check=True, capture_output=True)
            
            print(f"Updated {self.requirements_file}")
            
        except subprocess.CalledProcessError as e:
            print(f"Error updating requirements: {e}")
            raise
            
    def validate_requirements_integrity(self) -> bool:
        """Validate that requirements.txt hashes match installed packages"""
        if not self.requirements_file.exists():
            return False
            
        try:
            # Read requirements file
            with open(self.requirements_file, 'r') as f:
                lines = f.readlines()
                
            # Extract package names and hashes
            packages = {}
            for line in lines:
                if line.strip() and not line.startswith('#'):
                    if ' --hash=' in line:
                        parts = line.split(' --hash=')
                        package_name = parts[0].split('==')[0].strip()
                        hash_value = parts[1].strip()
                        packages[package_name] = hash_value
                        
            # Verify installed packages match requirements
            result = subprocess.run([
                sys.executable, "-m", "pip", "list", "--format", "json"
            ], capture_output=True, text=True, check=True)
            
            installed_packages = json.loads(result.stdout)
            installed_dict = {pkg['name']: pkg['version'] for pkg in installed_packages}
            
            # Check if all required packages are installed
            for package_name in packages:
                if package_name not in installed_dict:
                    print(f"Missing package: {package_name}")
                    return False
                    
            print("Requirements integrity check passed")
            return True
            
        except (subprocess.CalledProcessError, json.JSONDecodeError, KeyError) as e:
            print(f"Error validating requirements: {e}")
            return False
            
    def generate_poetry_lock(self) -> None:
        """Generate poetry.lock file from pyproject.toml"""
        try:
            subprocess.run([
                "poetry", "lock", "--no-update"
            ], cwd=self.project_root, check=True, capture_output=True)
            
            print("Generated poetry.lock file")
            
        except subprocess.CalledProcessError as e:
            print(f"Error generating poetry.lock: {e}")
            raise
            
    def update_poetry_lock(self) -> None:
        """Update poetry.lock with latest versions"""
        try:
            subprocess.run([
                "poetry", "lock", "--update"
            ], cwd=self.project_root, check=True, capture_output=True)
            
            print("Updated poetry.lock file")
            
        except subprocess.CalledProcessError as e:
            print(f"Error updating poetry.lock: {e}")
            raise
            
    def validate_poetry_lock_integrity(self) -> bool:
        """Validate poetry.lock integrity"""
        if not self.poetry_lock_file.exists():
            return False
            
        try:
            # Read lock file
            with open(self.poetry_lock_file, 'r') as f:
                content = f.read()
                
            # Basic integrity check - verify it's valid TOML
            import toml
            toml.loads(content)
            
            print("Poetry lock file integrity check passed")
            return True
            
        except Exception as e:
            print(f"Error validating poetry.lock: {e}")
            return False
            
    def get_dependency_tree(self) -> Dict:
        """Get dependency tree for security analysis"""
        try:
            result = subprocess.run([
                sys.executable, "-m", "pip", "deptree", "--packages", 
                "pip", "setuptools", "wheel"
            ], capture_output=True, text=True, check=True)
            
            return {"dependency_tree": result.stdout}
            
        except subprocess.CalledProcessError:
            # Fallback to basic pip list
            try:
                result = subprocess.run([
                    sys.executable, "-m", "pip", "list", "--format", "json"
                ], capture_output=True, text=True, check=True)
                
                return {"packages": json.loads(result.stdout)}
                
            except Exception:
                return {"error": "Could not retrieve dependency tree"}
                
    def create_dependency_manifest(self) -> None:
        """Create a manifest file with dependency information"""
        manifest = {
            "generated_at": str(subprocess.run([
                sys.executable, "-c", "import datetime; print(datetime.datetime.now())"
            ], capture_output=True, text=True).stdout.strip()),
            "requirements_file": str(self.requirements_file),
            "poetry_lock_file": str(self.poetry_lock_file),
            "dependencies": []
        }
        
        if self.requirements_file.exists():
            with open(self.requirements_file, 'r') as f:
                for line in f:
                    if line.strip() and not line.startswith('#'):
                        if '==' in line:
                            package, version = line.split('==')
                            manifest["dependencies"].append({
                                "name": package.strip(),
                                "version": version.split('#')[0].strip(),
                                "type": "pip"
                            })
                            
        manifest_file = self.project_root / "dependency_manifest.json"
        with open(manifest_file, 'w') as f:
            json.dump(manifest, f, indent=2)
            
        print(f"Created dependency manifest at {manifest_file}")

def main():
    manager = DependencyManager()
    
    # Generate requirements with hashes
    manager.generate_requirements_with_hashes()
    
    # Validate integrity
    manager.validate_requirements_integrity()
    
    # Generate poetry lock if needed
    if manager.pyproject_file.exists():
        manager.generate_poetry_lock()
        manager.validate_poetry_lock_integrity()
    
    # Create manifest
    manager.create_dependency_manifest()
    
    print("Dependency management process completed successfully")

